  ('0933805b-05b5-56e8-984f-a210fe59aeac'::uuid, 'hsse', 'approved'::entry_status, '{"source_file":"2026-05-03 Weekly Information Report (1).docx","report_label":"27 April - 03 May 2026","starts_on":"2026-04-27","ends_on":"2026-05-03","department_id":"hsse","paragraphs":[],"tables":[{"rows":[["Incident Code","Date","Brief Description"],["ALB0426FI001","28-Apr-26","A fire was reported on April 28/2026 next to Pad D VRU. The fire was put out by the employees using the fire extinguishers. The fire truck arrived on the scene but already the fire was extinguished. The operator had a minor burn on his face and hand. The first aid was administered by the on duty medic."]]},{"rows":[["ID","Brief Description"],["1","Responded on H2S alarm twice at K24A and Pad D"],["2","Continue the inspection for all the fire extinguishers at the field by the contractor."],["3","Air pack drills performed with 3 crews."],["4","Two air pack drills conducted last week."],["5","Received the notification of Regional Environmental Agency on re-inspection of Ecopit 4 and its permit."]]},{"rows":[["ID","Brief Description"],["1","Continue cooperating with tech support team for hot work permits 13 in total."],["2","21 Site Work Inspections performed by HS Team."],["3","Conducted 2 lease inspections at L34A and N27C."],["4","One safety inspections performed by the HS team at AAP1"],["5","5 Gas readings requested by the operations team performed last week."],["6","Four tank trucks inspected and two service rig inspected RSS017 and CW015."],["7","Four safety supports performed by the HS Team at Pad D, Sat 3, M37A x2."],["8","191 fire extinguishers are inspected by the contractor and fire department."],["9","Continued waste segregation and management at plastic site."],["10","Continued Ecopits level monitoring and management. Ecopit 7 actual level is 21 cm. Ecopit receiving materials are; Ecopit 3 - level 58 cm and Ecopit 8 - level 26 cm."],["11","Inspected ecopits as per schedule."],["12","Inspected the secondary containment at Seman Bridge."],["13","Completed the quarterly reporting of Oil and Gas exploration and production permit."],["14","Communication with National Environmental Agency in regards to e-Albania permitting reporting issues."],["15","Sent to AKBN the information on water and waste generated during 2025 in Patos Marinez oilfield."]]}],"subsections":[{"title":"HSSE","paragraphs":[],"tables":[]},{"title":"INCIDENTS","paragraphs":[],"tables":[{"rows":[["Incident Code","Date","Brief Description"],["ALB0426FI001","28-Apr-26","A fire was reported on April 28/2026 next to Pad D VRU. The fire was put out by the employees using the fire extinguishers. The fire truck arrived on the scene but already the fire was extinguished. The operator had a minor burn on his face and hand. The first aid was administered by the on duty medic."]]}]},{"title":"STATUS","paragraphs":[],"tables":[{"rows":[["ID","Brief Description"],["1","Responded on H2S alarm twice at K24A and Pad D"],["2","Continue the inspection for all the fire extinguishers at the field by the contractor."],["3","Air pack drills performed with 3 crews."],["4","Two air pack drills conducted last week."],["5","Received the notification of Regional Environmental Agency on re-inspection of Ecopit 4 and its permit."]]}]},{"title":"ACTIONS","paragraphs":[],"tables":[{"rows":[["ID","Brief Description"],["1","Continue cooperating with tech support team for hot work permits 13 in total."],["2","21 Site Work Inspections performed by HS Team."],["3","Conducted 2 lease inspections at L34A and N27C."],["4","One safety inspections performed by the HS team at AAP1"],["5","5 Gas readings requested by the operations team performed last week."],["6","Four tank trucks inspected and two service rig inspected RSS017 and CW015."],["7","Four safety supports performed by the HS Team at Pad D, Sat 3, M37A x2."],["8","191 fire extinguishers are inspected by the contractor and fire department."],["9","Continued waste segregation and management at plastic site."],["10","Continued Ecopits level monitoring and management. Ecopit 7 actual level is 21 cm. Ecopit receiving materials are; Ecopit 3 - level 58 cm and Ecopit 8 - level 26 cm."],["11","Inspected ecopits as per schedule."],["12","Inspected the secondary containment at Seman Bridge."],["13","Completed the quarterly reporting of Oil and Gas exploration and production permit."],["14","Communication with National Environmental Agency in regards to e-Albania permitting reporting issues."],["15","Sent to AKBN the information on water and waste generated during 2025 in Patos Marinez oilfield."]]}]}]}'::jsonb, now()),
