  ('fdcdde5e-2412-5c8d-b22a-0ffee91acfad'::uuid, 'hsse', 'approved'::entry_status, '{"source_file":"2026-05-24 Weekly Information Report (1).docx","report_label":"28-24 May 2026","starts_on":"2026-05-18","ends_on":"2026-05-24","department_id":"hsse","paragraphs":[],"tables":[{"rows":[["Incident Code","Date","Brief Description"],["","","No incidents recorded last week."]]},{"rows":[["ID","Brief Description"],["1","Safety orientation was done with 15 visitors."],["2","Conducted monthly safety meeting with different crews. (BPAL and Contractors)"]]},{"rows":[["ID","Brief Description"],["1","Continue cooperating with tech support team for hot work permits 14 in total and Confined space entry 3."],["2","18 Site Work Inspections performed by HS Team."],["3","Safety team has been on 4 safety supports at O29A, M37A, L26A x 2."],["4","There were 7 safety inspections performed by the HS team."],["5","12 Gas readings requested by the operations team performed last week."],["6","Two tank trucks inspected and two service rigs."],["7","04 fire suppression systems inspected by the fire department."],["8","Fire department has been for support with the fire truck at O29A, G31A x3 and L24A."],["9","Continued waste segregation and management at plastic site."],["10","Continued Ecopits level monitoring and management. Ecopit 7 actual level is 27 cm. Ecopit receiving materials are; Ecopit 3 - level 75 cm and Ecopit 8 - level 25 cm."],["11","Sent to Fier Regional Environmental Agency the contest on official record of Ecopit 4 inspection."],["12","Sent a notification to National Environmental Agency in regards to issues with e-Albania reporting."],["13","Completed the quarterly reporting of plastic site permit."],["14","A visit was paid at GWS pyrolysis site for the upcoming agreement on recycling of used tires."],["15","Received Polyeco representatives and collected sludge samples at Ecopit 4 and 8 in the light of mutual interest for Ecopits'' material reuse."]]}],"subsections":[{"title":"HSSE","paragraphs":[],"tables":[]},{"title":"INCIDENTS","paragraphs":[],"tables":[{"rows":[["Incident Code","Date","Brief Description"],["","","No incidents recorded last week."]]}]},{"title":"STATUS","paragraphs":[],"tables":[{"rows":[["ID","Brief Description"],["1","Safety orientation was done with 15 visitors."],["2","Conducted monthly safety meeting with different crews. (BPAL and Contractors)"]]}]},{"title":"ACTIONS","paragraphs":[],"tables":[{"rows":[["ID","Brief Description"],["1","Continue cooperating with tech support team for hot work permits 14 in total and Confined space entry 3."],["2","18 Site Work Inspections performed by HS Team."],["3","Safety team has been on 4 safety supports at O29A, M37A, L26A x 2."],["4","There were 7 safety inspections performed by the HS team."],["5","12 Gas readings requested by the operations team performed last week."],["6","Two tank trucks inspected and two service rigs."],["7","04 fire suppression systems inspected by the fire department."],["8","Fire department has been for support with the fire truck at O29A, G31A x3 and L24A."],["9","Continued waste segregation and management at plastic site."],["10","Continued Ecopits level monitoring and management. Ecopit 7 actual level is 27 cm. Ecopit receiving materials are; Ecopit 3 - level 75 cm and Ecopit 8 - level 25 cm."],["11","Sent to Fier Regional Environmental Agency the contest on official record of Ecopit 4 inspection."],["12","Sent a notification to National Environmental Agency in regards to issues with e-Albania reporting."],["13","Completed the quarterly reporting of plastic site permit."],["14","A visit was paid at GWS pyrolysis site for the upcoming agreement on recycling of used tires."],["15","Received Polyeco representatives and collected sludge samples at Ecopit 4 and 8 in the light of mutual interest for Ecopits'' material reuse."]]}]}]}'::jsonb, now()),
